/**
 * A hook that detects whether the current viewport width is below the mobile breakpoint (768px).
 *
 * Uses `window.matchMedia` to listen for viewport changes and returns `true` when the viewport is
 * narrower than `768px`. Returns `false` during SSR and the first render on the client.
 *
 * ### Return Value
 *
 * | Type      | Description                                          |
 * | :-------- | :--------------------------------------------------- |
 * | `boolean` | `true` if viewport width is below `768px`, else `false` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * function MyComponent() {
 *   const isMobile = useIsMobile();
 *   return isMobile ? <MobileNav /> : <DesktopNav />;
 * }
 * ```
 */
declare function useIsMobile(): boolean;

export { useIsMobile };
